"""
Скрипт добавления задания 3 ЕГЭ база «Графики и диаграммы».
Источник: Е.А. Ширяева, ЕГЭбаз 2026, задание №03.

Особенности:
- В question сохраняется полный текст для пользователя: пояснение к рисунку/таблице + конкретный вопрос.
- Для каждого задания указан конкретный image_path.
- Если несколько подпунктов относятся к одному рисунку, они используют одно и то же изображение.

Изображения положи в папку: app/images_b/n3/
Имена файлов: img_001.png ... img_070.png

Примеры:
- img_001.png используется для заданий 1.1, 1.2, 1.3;
- img_002.png используется для заданий 2.1, 2.2, 2.3.

Запуск: python add_eb03.py
"""

import asyncio
import aiosqlite
import os

_dir = os.path.dirname(os.path.abspath(__file__))
BASE_DIR = os.path.dirname(_dir)
DB_PATH = os.path.join(BASE_DIR, "app", "bot_database.db")

EXAM_TYPE = "ege_base"
TASK_NUMBER = 3
TOPIC = "ege_b03_graphs"
IMAGE_DIR = os.path.join(BASE_DIR, "app", "images_b", "n3")

TASKS: list[tuple[str, str, str | None, str]] = []


def img(n: int) -> str:
    return os.path.join(IMAGE_DIR, f"img_{n:03d}.png")


def add(figure: int, question: str, answer: str) -> None:
    TASKS.append((question.strip(), answer, img(figure), TOPIC))


