async def main() -> None:
    print(f"База данных: {DB_PATH}")
    print(f"Задач подготовлено: {len(TASKS)}")
    print(f"Папка с изображениями: {IMAGE_DIR}")

    missing_images = sorted({image_path for _, _, image_path, _ in TASKS if image_path and not os.path.exists(image_path)})
    if missing_images:
        print("❌ Не найдены изображения:")
        for path in missing_images:
            print("  -", path)
        return

    async with aiosqlite.connect(DB_PATH) as db:
        async with db.execute(
            "SELECT COUNT(*) FROM tasks WHERE exam_type=? AND task_number=?",
            (EXAM_TYPE, TASK_NUMBER),
        ) as cur:
            (count,) = await cur.fetchone()

        if count > 0:
            ans = input(
                f"В БД уже есть {count} записей для {EXAM_TYPE}, задание {TASK_NUMBER}. "
                "Удалить и загрузить заново? [y/N]: "
            ).strip().lower()
            if ans == "y":
                await db.execute(
                    "DELETE FROM tasks WHERE exam_type=? AND task_number=?",
                    (EXAM_TYPE, TASK_NUMBER),
                )
                await db.commit()
                print(f"Удалено {count} старых записей.")
            else:
                print("Отмена.")
                return

        for question, answer, image_path, topic in TASKS:
            await db.execute(
                "INSERT INTO tasks "
                "(exam_type, task_number, topic, question, answer, image_path, set_id) "
                "VALUES (?, ?, ?, ?, ?, ?, ?)",
                (EXAM_TYPE, TASK_NUMBER, topic, question, answer, image_path, None),
            )
        await db.commit()
        print(f"✅ Добавлено {len(TASKS)} заданий ({EXAM_TYPE}, task_number={TASK_NUMBER}).")


if __name__ == "__main__":
    asyncio.run(main())
